export function getAll() { return ALL; }

export function getProducts({ category='', search='', sort='', page=1, perPage=36 }={}) {
  let r = [...ALL];
  if (category) r = r.filter(p => p.category === category);
  if (search) { const q=search.toLowerCase(); r=r.filter(p=>p.title.toLowerCase().includes(q)||p.category.toLowerCase().includes(q)); }
  if (sort==='price_asc') r.sort((a,b)=>a.price-b.price);
  else if (sort==='price_desc') r.sort((a,b)=>b.price-a.price);
  else if (sort==='popular') r.sort((a,b)=>b.watchers-a.watchers);
  else if (sort==='sold') r.sort((a,b)=>b.sold-a.sold);
  else if (sort==='new') r.sort((a,b)=>b.id.localeCompare(a.id));
  const total = r.length;
  const totalPages = Math.ceil(total/perPage)||1;
  const items = r.slice((page-1)*perPage, page*perPage);
  return { items, total, totalPages, page };
}

export function getProduct(id) { return ALL.find(p=>p.id===id)||null; }

export function getCategories() {
  const m={};
  ALL.forEach(p=>{ m[p.category]=(m[p.category]||0)+1; });
  return Object.entries(m).sort((a,b)=>b[1]-a[1]);
}

export function getFeatured() {
  return ALL.filter(p=>p.photos.length>0).sort((a,b)=>b.watchers-a.watchers).slice(0,24);
}

export function getNewArrivals() {
  return ALL.filter(p=>p.photos.length>0).sort((a,b)=>b.id.localeCompare(a.id)).slice(0,12);
}

